import { Dispatch } from "redux";
import { AppThunk } from "../..";

import { apiList } from "../../actionNames";
import initDefaultAction, { APIResponseDetail } from "../../helper/default-action";
import initDefaultReducer from "../../helper/default-reducer";
import initialState from "../../helper/default-state";


export type PracticeRequestData = {
    id: string,
    parameter_name: string,
    unit: string,
    types: string,
    NDWQS_standard: string
}
const apiDetails = Object.freeze(apiList.practiceParameters.deletePracticeParameters);

export default function deleteTestParametersReducer(state = initialState, action= DefaultAction): DefaultState<PracticeRequestData>{
    const stateCopy = Object.assign({}, state);
    const actionName = apiDetails.actionName;

    return initDefaultReducer(actionName, action,stateCopy);
}

export const deletePracticeParametersAction = (id): AppThunk<APIResponseDetail<PracticeRequestData>> => async (dispatch: Dispatch) => {
    return await initDefaultAction(apiDetails, dispatch, { disableSuccessToast: true, pathVariables: { id } });
};
